# Turkish Q console map based on kbd/data/keymaps/i386/qwerty/trq.map.
# Layout source: Linux kbd project (GPL-2.0-or-later).
charset "UTF-8"
keymaps 0-7
alt_is_meta
keycode 1 = Escape
keycode 2 = one exclam
keycode 3 = two apostrophe sterling
keycode 4 = three asciicircum numbersign
keycode 5 = four plus dollar
keycode 6 = five percent onehalf
keycode 7 = six ampersand
keycode 8 = seven slash braceleft
keycode 9 = eight parenleft bracketleft
keycode 10 = nine parenright bracketright
keycode 11 = zero equal braceright
keycode 12 = asterisk question backslash
keycode 13 = minus underscore bar
keycode 14 = Delete
keycode 15 = Tab
keycode 16 = +q +Q at
keycode 17 = +w +W
keycode 18 = +e +E euro
keycode 19 = +r +R
keycode 20 = +t +T
keycode 21 = +y +Y
keycode 22 = +u +U +ucircumflex +Ucircumflex
keycode 23 = +dotlessi +I +icircumflex +Icircumflex
keycode 24 = +o +O +ocircumflex +Ocircumflex
keycode 25 = +p +P
keycode 26 = +gbreve +Gbreve diaeresis
keycode 27 = +udiaeresis +Udiaeresis asciitilde
keycode 28 = Return
keycode 30 = +a +A +acircumflex +Acircumflex
keycode 31 = +s +S
keycode 32 = +d +D
keycode 33 = +f +F
keycode 34 = +g +G
keycode 35 = +h +H
keycode 36 = +j +J
keycode 37 = +k +K
keycode 38 = +l +L
keycode 39 = +scedilla +Scedilla acute
keycode 40 = +i +Idotabove
keycode 41 = quotedbl eacute
keycode 43 = comma semicolon grave
keycode 44 = +z +Z
keycode 45 = +x +X
keycode 46 = +c +C
keycode 47 = +v +V
keycode 48 = +b +B
keycode 49 = +n +N
keycode 50 = +m +M
keycode 51 = +odiaeresis +Odiaeresis
keycode 52 = +ccedilla +Ccedilla
keycode 53 = period colon
keycode 57 = space
control keycode 57 = nul
keycode 86 = less greater bar
